<template>
	<view class="pet-item">
		<!-- 宠物图片，通过props传入 -->
		<img :src="imageUrl" alt="" class="pet-image" />

		<view class="pet-item-content">
			<!-- 宠物类型，通过props传入 -->
			<span class="pet-type">{{ petType }}</span>

			<!-- 宠物描述信息，通过props传入 -->
			<span class="discribe">{{ description }}</span>

			<!-- 宠物性格标签，通过props传入数组 -->
			<view class="pet-label flex">
				<view class="tag" v-for="(tag, index) in personalityTags" :key="index">
					<u-tag :text="tag.text" :type="tag.type || ''" size="mini"
						:plain="tag.plain !== undefined ? tag.plain : true" :plainFill="tag.plainFill"></u-tag>
				</view>
			</view>

			<!-- 宠物状态标签，通过props传入数组 -->
			<view class="pet-status flex">
				<view class="tag" v-for="(status, index) in statusTags" :key="index">
					<u-tag :icon="status.icon" :text="status.text" size="mini" :type="status.type || 'primary'"></u-tag>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		name: 'PetCard',
		options: {
			styleIsolation: 'shared'
		},
		// 定义可传入的属性
		props: {
			// 宠物图片URL
			imageUrl: {
				type: String,
				required: true,
				default: ''
			},
			// 宠物类型（如金毛）
			petType: {
				type: String,
				required: true,
				default: ''
			},
			// 宠物描述（如三岁|公）
			description: {
				type: String,
				required: true,
				default: ''
			},
			// 宠物性格标签数组
			personalityTags: {
				type: Array,
				required: true,
				default: () => []
			},
			// 宠物状态标签数组
			statusTags: {
				type: Array,
				required: true,
				default: () => []
			}
		}
	}
</script>

<style lang="scss">
	.pet-item {
		box-sizing: border-box;
		margin-bottom: 20rpx;
		border-radius: 20rpx;
		border: 4rpx solid #6988cc;
		height: 202rpx;
		display: flex;
		overflow: hidden;

		.pet-item-content {
			margin: 10rpx 20rpx;
			display: flex;
			flex-direction: column;

			.pet-type {
				font-weight: 600;
			}

			.discribe {
				margin: 10rpx 0;
				font-size: 25rpx;
				color: #7b7b7b;
			}



			.pet-label {
				padding: 10rpx 0;
				box-sizing: border-box;
				border-bottom: 1px solid #c3c3c3;

				.u-tag--mini {
					height: 20rpx !important;
				}

				.u-tag__text--mini {
					font-size: 20rpx !important;
				}

				.tag {
					margin-right: 10rpx;
				}

			}

			.pet-status {
				margin-top: 10rpx;

				.tag {
					margin-right: 16rpx;
				}

				.u-tag--mini {
					height: 25rpx !important;
				}

				.u-icon__icon {
					font-size: 20rpx !important;
				}

				.u-tag__text--mini {
					font-size: 18rpx !important;
				}

			}
		}

		image {
			width: 200rpx;
			height: 200rpx;

		}
	}
</style>